type objectWhere[Q psql.Filterable] struct {
	ID              psql.WhereMod[Q, uuid.UUID]
	ClusterID       psql.WhereMod[Q, uuid.UUID]
	Namespace       psql.WhereMod[Q, string]
	Name            psql.WhereMod[Q, string]
	ResourceVersion psql.WhereMod[Q, string]
	Kind            psql.WhereMod[Q, string]
	Raw             psql.WhereNullMod[Q, types.JSON[json.RawMessage]]
	HealthStatus    psql.WhereMod[Q, string]
	CreatedAt       psql.WhereMod[Q, time.Time]
	RunVersion      psql.WhereMod[Q, uuid.UUID]
}

func (objectWhere[Q]) AliasedAs(alias string) objectWhere[Q] {
	return buildObjectWhere[Q](buildObjectColumns(alias))
}

func buildObjectWhere[Q psql.Filterable](cols objectColumns) objectWhere[Q] {
	return objectWhere[Q]{
		ID:              psql.Where[Q, uuid.UUID](cols.ID),
		ClusterID:       psql.Where[Q, uuid.UUID](cols.ClusterID),
		Namespace:       psql.Where[Q, string](cols.Namespace),
		Name:            psql.Where[Q, string](cols.Name),
		ResourceVersion: psql.Where[Q, string](cols.ResourceVersion),
		Kind:            psql.Where[Q, string](cols.Kind),
		Raw:             psql.WhereNull[Q, types.JSON[json.RawMessage]](cols.Raw),
		HealthStatus:    psql.Where[Q, string](cols.HealthStatus),
		CreatedAt:       psql.Where[Q, time.Time](cols.CreatedAt),
		RunVersion:      psql.Where[Q, uuid.UUID](cols.RunVersion),
	}
}

func (o *Object) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "Cluster":
		rel, ok := retrieved.(*Cluster)
		if !ok {
			return fmt.Errorf("object cannot load %T as %q", retrieved, name)
		}

		o.R.Cluster = rel

		if rel != nil {
			rel.R.Objects = ObjectSlice{o}
		}
		return nil
	case "UnmatchedComponents":
		rels, ok := retrieved.(UnmatchedComponentSlice)
		if !ok {
			return fmt.Errorf("object cannot load %T as %q", retrieved, name)
		}

		o.R.UnmatchedComponents = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Object = o
			}
		}
		return nil
	case "UpgradeableComponents":
		rels, ok := retrieved.(UpgradeableComponentSlice)
		if !ok {
			return fmt.Errorf("object cannot load %T as %q", retrieved, name)
		}

		o.R.UpgradeableComponents = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Object = o
			}
		}
		return nil
	default:
		return fmt.Errorf("object has no relationship %q", name)
	}
}

type objectPreloader struct {
	Cluster func(...psql.PreloadOption) psql.Preloader
}

func buildObjectPreloader() objectPreloader {
	return objectPreloader{
		Cluster: func(opts ...psql.PreloadOption) psql.Preloader {
			return psql.Preload[*Cluster, ClusterSlice](psql.PreloadRel{
				Name: "Cluster",
				Sides: []psql.PreloadSide{
					{
						From:        Objects,
						To:          Clusters,
						FromColumns: []string{"cluster_id"},
						ToColumns:   []string{"id"},
					},
				},
			}, Clusters.Columns.Names(), opts...)
		},
	}
}

type objectThenLoader[Q orm.Loadable] struct {
	Cluster               func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	UnmatchedComponents   func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	UpgradeableComponents func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
}

func buildObjectThenLoader[Q orm.Loadable]() objectThenLoader[Q] {
	type ClusterLoadInterface interface {
		LoadCluster(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type UnmatchedComponentsLoadInterface interface {
		LoadUnmatchedComponents(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type UpgradeableComponentsLoadInterface interface {
		LoadUpgradeableComponents(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}

	return objectThenLoader[Q]{
		Cluster: thenLoadBuilder[Q](
			"Cluster",
			func(ctx context.Context, exec bob.Executor, retrieved ClusterLoadInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadCluster(ctx, exec, mods...)
			},
		),
		UnmatchedComponents: thenLoadBuilder[Q](
			"UnmatchedComponents",
			func(ctx context.Context, exec bob.Executor, retrieved UnmatchedComponentsLoadInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadUnmatchedComponents(ctx, exec, mods...)
			},
		),
		UpgradeableComponents: thenLoadBuilder[Q](
			"UpgradeableComponents",
			func(ctx context.Context, exec bob.Executor, retrieved UpgradeableComponentsLoadInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadUpgradeableComponents(ctx, exec, mods...)
			},
		),
	}
}

// LoadCluster loads the object's Cluster into the .R struct
func (o *Object) LoadCluster(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.Cluster = nil

	related, err := o.Cluster(mods...).One(ctx, exec)
	if err != nil {
		return err
	}

	related.R.Objects = ObjectSlice{o}

	o.R.Cluster = related
	return nil
}

// LoadCluster loads the object's Cluster into the .R struct
func (os ObjectSlice) LoadCluster(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	clusters, err := os.Cluster(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range clusters {

			if !(o.ClusterID == rel.ID) {
				continue
			}

			rel.R.Objects = append(rel.R.Objects, o)

			o.R.Cluster = rel
			break
		}
	}

	return nil
}

