type objectJoins[Q dialect.Joinable] struct {
	typ                   string
	Cluster               modAs[Q, clusterColumns]
	UnmatchedComponents   modAs[Q, unmatchedComponentColumns]
	UpgradeableComponents modAs[Q, upgradeableComponentColumns]
}

func (j objectJoins[Q]) aliasedAs(alias string) objectJoins[Q] {
	return buildObjectJoins[Q](buildObjectColumns(alias), j.typ)
}

func buildObjectJoins[Q dialect.Joinable](cols objectColumns, typ string) objectJoins[Q] {
	return objectJoins[Q]{
		typ: typ,
		Cluster: modAs[Q, clusterColumns]{
			c: Clusters.Columns,
			f: func(to clusterColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Clusters.Name().As(to.Alias())).On(
						to.ID.EQ(cols.ClusterID),
					))
				}

				return mods
			},
		},
		UnmatchedComponents: modAs[Q, unmatchedComponentColumns]{
			c: UnmatchedComponents.Columns,
			f: func(to unmatchedComponentColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, UnmatchedComponents.Name().As(to.Alias())).On(
						to.ClusterID.EQ(cols.ClusterID), to.ObjectID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		UpgradeableComponents: modAs[Q, upgradeableComponentColumns]{
			c: UpgradeableComponents.Columns,
			f: func(to upgradeableComponentColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, UpgradeableComponents.Name().As(to.Alias())).On(
						to.ClusterID.EQ(cols.ClusterID), to.ObjectID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
	}
}
